{
  "mitigation_currently_implemented": "Configure firewall rules on the UbuntuComputer to restrict file access and disable reading sensitive file types like .png, .yml, and .wav by non-system processes",
  "comments": "Configured iptables firewall rules on the UbuntuComputer to drop outgoing traffic on port 8443 containing sensitive file extensions .png, .yml, and .wav. This mitigation aims to prevent exfiltration of these sensitive file types over the attacker's command and control channel while the attacker remains active on the host.",
  "device_identifier": "UbuntuComputer",
  "commands": [
    "iptables -A OUTPUT -p tcp --dport 8443 -m string --string \".png\" --algo kmp -j DROP",
    "iptables -A OUTPUT -p tcp --dport 8443 -m string --string \".yml\" --algo kmp -j DROP",
    "iptables -A OUTPUT -p tcp --dport 8443 -m string --string \".wav\" --algo kmp -j DROP"
  ]
}

{
  "mitigation_currently_implemented": "Deploy Snort IPS inline between UbuntuComputer and the network gateway to detect and block malicious exfiltration activity and archive file transfers over encrypted channels",
  "comments": "Added a Snort IDS/IPS device configured to block malicious traffic. Attempted to link it inline between UbuntuComputer and the network gateway, but since UbuntuComputer has no available network adapter slots, the Snort device was linked upstream between the existing FortiGate device and the internet gateway. This placement enables Snort to monitor and block malicious exfiltration activity effectively at the network edge, limiting the attacker's ability to exfiltrate data.",
  "device_identifier": "snort-ips-1",
  "commands": [
    "add network device snort-ips-1",
    "link snort-ips-1 FortiGate7.0.14-1"
  ]
